import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface CalendarEvent {
  event: string;
  time: string;
}

interface OutfitSuggestion {
  occasion: string;
  outfit: string;
  accessories: string[];
}

interface WardrobeData {
  location: string;
  weather: {
    currentTemp: number;
    condition: string;
  };
  calendarEvents: CalendarEvent[];
  outfitSuggestions: OutfitSuggestion[];
}

export default function Widget() {
  const data = response.data as WardrobeData;
  const { location, weather, calendarEvents, outfitSuggestions } = data;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFF8E1' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Location: {location}
            </Typography>
            <Typography variant="h6" color="primary">
              {weather.currentTemp}° - {weather.condition}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Events Today
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {calendarEvents.map((event, index) => (
                <Chip key={index} label={`${event.time} - ${event.event}`} sx={{ fontSize: '11px', px: 1, py: 0.5 }} />
              ))}
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Outfit Suggestions
            </Typography>
            <Stack spacing={1}>
              {outfitSuggestions.map((suggestion, index) => (
                <Box key={index}>
                  <Typography variant="body2" sx={{ fontWeight: 'bold' }}>
                    {suggestion.occasion}
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    {suggestion.outfit}
                  </Typography>
                  <Stack direction="row" spacing={0.5}>
                    {suggestion.accessories.map((accessory, accIndex) => (
                      <Chip key={accIndex} label={accessory} sx={{ fontSize: '11px', px: 0.5, py: 0.2 }} />
                    ))}
                  </Stack>
                </Box>
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
